def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re

    # Helper to safely query database
    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Check if final_answer exists and is not empty
    if not final_answer or not isinstance(final_answer, str) or len(final_answer.strip()) == 0:
        return {"result": "others"}

    final_answer_lower = final_answer.lower()

    # Check 1: TSLA must be mentioned
    if "tsla" not in final_answer_lower:
        return {"result": "others"}

    # Get TSLA data from database to validate
    tsla_realtime = safe_query(final_db_path, 
        "SELECT frq.price, frq.price_change, frq.price_change_percent FROM finance_realtime_quotes frq JOIN finance_symbols fs ON frq.symbol_id = fs.id WHERE fs.symbol = ?", 
        ("TSLA",))

    if not tsla_realtime:
        return {"result": "others"}

    db_price = tsla_realtime[0][0]
    db_change = tsla_realtime[0][1]
    db_change_percent = tsla_realtime[0][2]

    # Check 2: Real-time quote/price must be present
    # Look for price patterns like $255.4, 255.4, or "price: 255.4"
    price_pattern = r"(\$?\s*\d+\.\d+|price[:\s]+\$?\s*\d+\.\d+)"
    price_matches = re.findall(price_pattern, final_answer, re.IGNORECASE)

    has_price = False
    if price_matches:
        # Extract numeric values and check if any match the database price
        for match in price_matches:
            numeric_match = re.search(r"\d+\.\d+", match)
            if numeric_match:
                price_value = float(numeric_match.group())
                # Allow for small floating point differences
                if abs(price_value - db_price) < 0.01:
                    has_price = True
                    break

    if not has_price:
        return {"result": "others"}

    # Check 3: Today's absolute price change must be present
    # Look for patterns like "-5.6", "$-5.6", "-$5.6", "change: -5.6", "down 5.6"
    absolute_change_pattern = r"(-?\$?\s*\d+\.\d+|change[:\s]+[-\$]?\s*\d+\.\d+|down\s+\$?\d+\.\d+|up\s+\$?\d+\.\d+)"
    change_matches = re.findall(absolute_change_pattern, final_answer, re.IGNORECASE)

    has_absolute_change = False
    if change_matches:
        for match in change_matches:
            numeric_match = re.search(r"-?\d+\.\d+", match)
            if numeric_match:
                change_value = abs(float(numeric_match.group()))
                # Check if it matches the database absolute change
                if abs(change_value - abs(db_change)) < 0.01:
                    has_absolute_change = True
                    break

    if not has_absolute_change:
        return {"result": "others"}

    # Check 4: Today's percentage change must be present
    # Look for patterns like "-2.14%", "2.14%", "change: -2.14%"
    percent_pattern = r"-?\d+\.\d+\s*%"
    percent_matches = re.findall(percent_pattern, final_answer)

    has_percent_change = False
    if percent_matches:
        for match in percent_matches:
            numeric_match = re.search(r"-?\d+\.\d+", match)
            if numeric_match:
                percent_value = abs(float(numeric_match.group()))
                # Check if it matches the database percentage change
                if abs(percent_value - abs(db_change_percent)) < 0.01:
                    has_percent_change = True
                    break

    if not has_percent_change:
        return {"result": "others"}

    # Check 5: 1-year performance chart data must be present
    # Get TSLA historical data from database
    tsla_history = safe_query(final_db_path,
        "SELECT date, close FROM finance_price_history_daily fph JOIN finance_symbols fs ON fph.symbol_id = fs.id WHERE fs.symbol = ? ORDER BY date",
        ("TSLA",))

    if not tsla_history or len(tsla_history) < 2:
        return {"result": "others"}

    # For 1-year chart data, we need to verify multiple historical data points are mentioned
    # Look for patterns indicating historical data: dates, multiple prices, or chart-related terms
    chart_indicators = [
        r"chart",
        r"historical",
        r"performance",
        r"year",
        r"2024",
        r"2023",
        r"\d{4}-\d{2}-\d{2}",  # Date pattern
        r"data\s*point",
        r"price\s*histor"
    ]

    chart_indicator_count = 0
    for indicator in chart_indicators:
        if re.search(indicator, final_answer, re.IGNORECASE):
            chart_indicator_count += 1

    # Need at least 2 chart-related indicators
    if chart_indicator_count < 2:
        return {"result": "others"}

    # Additionally, check if multiple historical prices are mentioned
    # Extract all price-like numbers from the answer
    all_numbers = re.findall(r"\d+\.\d+", final_answer)

    if len(all_numbers) < 3:  # Should have at least current price + 2 historical prices
        return {"result": "others"}

    # Check if any historical prices from database are mentioned
    historical_prices = [row[1] for row in tsla_history]
    matched_historical_prices = 0

    for num_str in all_numbers:
        try:
            num_val = float(num_str)
            for hist_price in historical_prices:
                if abs(num_val - hist_price) < 0.01:
                    matched_historical_prices += 1
                    break
        except ValueError:
            continue

    # Should have at least 2 historical price matches (indicating chart data is present)
    if matched_historical_prices < 2:
        return {"result": "others"}

    # All checks passed
    return {"result": "complete"}

