    current_weather_query = "SELECT temperature, condition FROM weather_current WHERE location_id = ?"
    current_weather = safe_query(final_db_path, current_weather_query, (seattle_location_id,))

    if not current_weather:
        return {"result": "others"}

    current_temp = current_weather[0][0]
    current_condition = current_weather[0][1]

    # Look for temperature in final_answer (allow for slight rounding variations)
    temp_pattern = r'(?:current|currently|now|temperature)[^.]*?(?:is|:|\s)(\d+(?:\.\d+)?)[\s°]*(?:F|degrees|fahrenheit)'
    temp_match = re.search(temp_pattern, final_answer, re.IGNORECASE)

    has_current_temp = False
    if temp_match:
        mentioned_temp = float(temp_match.group(1))
        # Allow for rounding within 2 degrees
        if abs(mentioned_temp - current_temp) <= 2.0:
            has_current_temp = True

    # Also check for simpler temperature mentions
    if not has_current_temp:
        simple_temp_pattern = r'(\d+(?:\.\d+)?)[\s°]*(?:F|degrees)'
        for match in re.finditer(simple_temp_pattern, final_answer):
            mentioned_temp = float(match.group(1))
            if abs(mentioned_temp - current_temp) <= 2.0:
                has_current_temp = True
                break

    if not has_current_temp:
        return {"result": "others"}

    # Check 2: Verify 5-day forecast is present
    forecast_query = "SELECT forecast_date, high_temp, low_temp, condition FROM weather_forecast_daily WHERE location_id = ? ORDER BY forecast_date"
    forecast_data = safe_query(final_db_path, forecast_query, (seattle_location_id,))

    if len(forecast_data) < 5:
