    # Take the first 5 days for verification
    forecast_5day = forecast_data[:5]

    # Check if forecast data is mentioned - look for multiple high/low temperature pairs
    high_low_pattern = r'(?:high|hi)[^\d]*(\d+)[^\d]*(?:low|lo)[^\d]*(\d+)'
    forecast_matches = re.findall(high_low_pattern, final_answer, re.IGNORECASE)

    # Alternative pattern: low then high
    low_high_pattern = r'(?:low|lo)[^\d]*(\d+)[^\d]*(?:high|hi)[^\d]*(\d+)'
    forecast_matches_alt = re.findall(low_high_pattern, final_answer, re.IGNORECASE)

    # We need at least 5 forecast entries mentioned
    total_forecast_mentions = len(forecast_matches) + len(forecast_matches_alt)

    if total_forecast_mentions < 5:
        return {"result": "others"}

    # Verify at least some forecast temperatures match database (allowing for rounding)
