        if final_first_start.hour != 11 or final_first_start.minute != 0:
            return {"result": "others"}

        # Calculate the time shift (should be 2 hours)
        time_shift = final_first_start - initial_first_start
        expected_shift = timedelta(hours=2)

        if time_shift != expected_shift:
            return {"result": "others"}

        # Duration should remain the same
        initial_duration = initial_first_end - initial_first_start
        final_duration = final_first_end - final_first_start
        if initial_duration != final_duration:
