    if not new_notes:
        return {"result": "others"}

    # Check each new note to see if it matches requirements
    for note in new_notes:
        note_id, note_type, note_text, related_res_id, pos_ref, amount_cents = note

        # Must be post_visit type
        if note_type != 'post_visit':
            continue

        # Must be linked to the March 15, 2026 reservation
        if related_res_id != reservation_id:
            continue

        # Must have amount of $180 (18000 cents)
        if amount_cents != 18000:
            continue

        # Must have POS check reference
        if not pos_ref:
            continue

        # Note text must mention key elements
        if not note_text:
            continue

        note_lower = note_text.lower()

        # Check for tasting menu
        tasting_menu_mentioned = bool(re.search(r'tasting\s+menu', note_lower))

        # Check for $180 or 180
        amount_mentioned = bool(re.search(r'\$?180', note_text))

        # Check for complimentary dessert
        dessert_mentioned = bool(re.search(r'complimentary\s+dessert', note_lower)) or bool(re.search(r'comp.*dessert', note_lower))

        # Check for next visit
        next_visit_mentioned = bool(re.search(r'next\s+visit', note_lower))

        # All conditions must be met
        if tasting_menu_mentioned and amount_mentioned and dessert_mentioned and next_visit_mentioned:
            return {"result": "complete"}

    return {"result": "others"}

def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
