            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Check if final_answer exists and is not empty
    if not final_answer or len(final_answer.strip()) < 20:
        return {"result": "others"}

    # Query the database for ground truth data
    # Get Riverfront Bistro's restaurant_id
    restaurant_query = "SELECT id FROM restaurants WHERE name = 'Riverfront Bistro'"
    restaurant_result = safe_query(final_db_path, restaurant_query)
    if not restaurant_result:
        return {"result": "others"}
    restaurant_id = restaurant_result[0][0]

    # Get all reservations for June 2026 (2026-06-01 to 2026-06-30)
    reservations_query = """
        SELECT r.party_size, r.booking_channel, r.scheduled_time, r.actual_seated_time, 
               r.completed_time, r.scheduled_date, mp.name as meal_period
        FROM reservations r
        LEFT JOIN meal_periods mp ON r.restaurant_id = mp.restaurant_id
        WHERE r.restaurant_id = ?
          AND r.scheduled_date >= '2026-06-01'
          AND r.scheduled_date <= '2026-06-30'
          AND r.status IN ('confirmed', 'completed', 'seated')
          AND r.status != 'cancelled'
    """
    reservations = safe_query(final_db_path, reservations_query, (restaurant_id,))

    if not reservations:
        # No reservations in the date range, check if the answer reflects this
        if re.search(r'(no|zero|0)\s+(reservation|booking|cover)', final_answer, re.IGNORECASE):
            return {"result": "complete"}
        return {"result": "others"}

    # Calculate ground truth metrics
    total_covers = 0
    channel_counts = {'online_widget': 0, 'phone': 0, 'walk_in': 0}
    meal_period_turn_times = {'Breakfast': [], 'Lunch': [], 'Dinner': []}

    for reservation in reservations:
        party_size, booking_channel, scheduled_time, actual_seated_time, completed_time, scheduled_date, meal_period = reservation

        # Count total covers
        total_covers += party_size

        # Count booking channels
        if booking_channel in channel_counts:
            channel_counts[booking_channel] += party_size

        # Calculate turn time if we have both seated and completed times
        if actual_seated_time and completed_time:
            try:
                # Parse times - they might be in different formats
                if 'T' in actual_seated_time:
                    seated_dt = datetime.fromisoformat(actual_seated_time)
                    completed_dt = datetime.fromisoformat(completed_time)
                else:
                    seated_dt = datetime.strptime(f"{scheduled_date} {actual_seated_time}", "%Y-%m-%d %H:%M:%S")
                    completed_dt = datetime.strptime(f"{scheduled_date} {completed_time}", "%Y-%m-%d %H:%M:%S")

                turn_time_minutes = (completed_dt - seated_dt).total_seconds() / 60

                # Determine meal period based on scheduled time
                scheduled_hour = int(scheduled_time.split(':')[0])
                if 7 <= scheduled_hour < 11:
                    meal_period_turn_times['Breakfast'].append(turn_time_minutes)
                elif 11 <= scheduled_hour < 15:
                    meal_period_turn_times['Lunch'].append(turn_time_minutes)
                elif 17 <= scheduled_hour < 23:
                    meal_period_turn_times['Dinner'].append(turn_time_minutes)
            except:
                pass

    # Calculate average turn times
    avg_turn_times = {}
    for period, times in meal_period_turn_times.items():
        if times:
            avg_turn_times[period] = sum(times) / len(times)

    # Check 1: Verify total covers is mentioned
    total_covers_found = False
    covers_pattern = r'total\s+covers?[:\s]+(\d+)'
    covers_match = re.search(covers_pattern, final_answer, re.IGNORECASE)
    if covers_match:
        reported_covers = int(covers_match.group(1))
        if reported_covers == total_covers:
            total_covers_found = True
    else:
        # Try alternative patterns
        if re.search(rf'\b{total_covers}\b.*covers?', final_answer, re.IGNORECASE):
            total_covers_found = True

    # Check 2: Verify booking channel distribution is present
    channels_found = 0
    for channel in ['online_widget', 'phone', 'walk_in']:
        channel_display = channel.replace('_', ' ')
        if re.search(rf'{channel_display}|{channel}|online\s+widget|walk-in|walkin', final_answer, re.IGNORECASE):
            channels_found += 1

    # Check 3: Verify average turn time by meal period is present
    meal_periods_found = 0
    for period in ['Breakfast', 'Lunch', 'Dinner']:
        if re.search(rf'{period}', final_answer, re.IGNORECASE):
            # Check if there's a time/duration mentioned near the meal period
            period_section = re.search(rf'{period}[^\n]{{0,200}}', final_answer, re.IGNORECASE)
            if period_section:
                section_text = period_section.group(0)
                if re.search(r'\d+\s*(min|minute|hour|hr)', section_text, re.IGNORECASE):
                    meal_periods_found += 1

    # Check if report mentions the correct restaurant and date range
    restaurant_mentioned = bool(re.search(r'Riverfront\s+Bistro', final_answer, re.IGNORECASE))
    date_range_mentioned = bool(re.search(r'June|06[/-]\d{2}[/-]20?26|2026-06', final_answer, re.IGNORECASE))

    # Determine if task is complete
    # Must have: restaurant name, date range, total covers, booking channels, and meal period turn times
    if (restaurant_mentioned and date_range_mentioned and total_covers_found and 
        channels_found >= 2 and meal_periods_found >= 1):
        return {"result": "complete"}

    return {"result": "others"}

