    # Check if average is within reasonable tolerance (0.1)
    if abs(extracted_avg - expected_avg) > 0.1:
        return {"result": "others"}

    # Check for department distribution
    dept_found = {}
    for dept_name in dept_distribution.keys():
        dept_count = dept_distribution[dept_name]
