    expected_rate = round(base_rate * 1.15, 2)

    # Calculate all Fridays and Saturdays in July and August 2025
    fridays_saturdays = []
    for month in [7, 8]:
        start_date = datetime(2025, month, 1)
        if month == 7:
            end_date = datetime(2025, 7, 31)
        else:
            end_date = datetime(2025, 8, 31)

        current = start_date
        while current <= end_date:
            weekday = current.weekday()
            if weekday == 4 or weekday == 5:  # Friday=4, Saturday=5
                fridays_saturdays.append(current.strftime('%Y-%m-%d'))
            current += timedelta(days=1)

    if len(fridays_saturdays) == 0:
        return {"result": "others"}

    # Check all Friday/Saturday dates have correct overrides
    overrides = safe_query(final_db_path,
        "SELECT date, nightly_rate, min_stay_nights FROM rate_plan_overrides WHERE rate_plan_id = ? ORDER BY date",
        (602,))

    override_dict = {}
    for override in overrides:
        override_dict[override[0]] = {'nightly_rate': override[1], 'min_stay_nights': override[2]}

    # Verify all Friday/Saturday dates have correct overrides
    for date_str in fridays_saturdays:
        if date_str not in override_dict:
            return {"result": "others"}

        override = override_dict[date_str]
        if override['nightly_rate'] is None or abs(override['nightly_rate'] - expected_rate) > 0.01:
            return {"result": "others"}

        if override['min_stay_nights'] != 3:
            return {"result": "others"}

    # Check that minimum stay requirement is enforced for July 1 - August 31
    # This can be done by either:
    # 1. Having overrides for ALL dates in the range with min_stay_nights=3, OR
    # 2. Updating the base rate_plan min_stay_nights to 3

    # Generate all dates from July 1 to August 31, 2025
    all_dates_in_range = []
    current = datetime(2025, 7, 1)
    end = datetime(2025, 8, 31)
    while current <= end:
        all_dates_in_range.append(current.strftime('%Y-%m-%d'))
        current += timedelta(days=1)

    # Check if all dates have min_stay_nights = 3 in overrides
    all_dates_have_min_stay = True
    for date_str in all_dates_in_range:
        if date_str not in override_dict:
            all_dates_have_min_stay = False
            break
        if override_dict[date_str]['min_stay_nights'] != 3:
            all_dates_have_min_stay = False
            break

