    lines = final_answer.split('\n')
    for line in lines:
        email_match = re.search(email_pattern, line)
        if email_match:
            email = email_match.group(0)
            # Look for numbers that could be click counts (typically 1-4 digits)
            number_matches = re.findall(r'\b(\d{1,4})\b', line)
            # Look for dates in various formats
            date_matches = re.findall(r'\d{4}-\d{2}-\d{2}', line)

            if number_matches:
                # Take the first reasonable number as click count
                click_count = int(number_matches[0])
                last_click_date = date_matches[0] if date_matches else None
                extracted_contacts.append({
