    FROM contacts c
    INNER JOIN campaign_recipients cr ON c.id = cr.contact_id
    INNER JOIN campaigns cp ON cr.campaign_id = cp.id
    INNER JOIN campaign_clicks cc ON cr.id = cc.campaign_recipient_id
    WHERE c.audience_id = ?
    AND cp.sent_at >= ?
    AND cp.sent_at IS NOT NULL
    GROUP BY c.id, c.email
    ORDER BY total_clicks DESC, last_click_date DESC
    LIMIT 10
    """

