        no_data_indicators = ['no contacts', 'no results', 'no data', 'empty', '0 contacts', 'zero contacts']
        if any(indicator in final_answer.lower() for indicator in no_data_indicators):
            return {"result": "complete"}
        return {"result": "others"}

    # Convert db results to comparable format
    db_contact_dict = {}
    for email, clicks, last_date in db_contacts:
        db_contact_dict[email.lower()] = {
            'clicks': clicks,
            'last_click_date': last_date.split()[0] if last_date else None
        }

    # Check if extracted contacts match database contacts
    # Need at least 70% of expected contacts to be present
    expected_count = len(db_contacts)
    matched_count = 0

    for ext_contact in extracted_contacts:
        email = ext_contact['email']
        if email in db_contact_dict:
            db_data = db_contact_dict[email]
            # Check if click count matches
            if ext_contact['clicks'] == db_data['clicks']:
                matched_count += 1

    # Require at least 70% match and minimum contacts
    if expected_count > 0 and matched_count >= max(3, int(0.7 * expected_count)):
        # Additional check: verify top contacts are present
        top_3_emails = [email.lower() for email, _, _ in db_contacts[:min(3, len(db_contacts))]]
        extracted_emails = [ec['email'] for ec in extracted_contacts]

        top_matched = sum(1 for email in top_3_emails if email in extracted_emails)
        if top_matched >= min(2, len(top_3_emails)):
