    total_match = re.search(total_pattern, final_answer, re.IGNORECASE)

    # Win count
    win_pattern = r'(?:wins?|won)[:\s]*?(\d+)'
    win_match = re.search(win_pattern, final_answer, re.IGNORECASE)

    # Loss count
    loss_pattern = r'(?:loss(?:es)?|lost)[:\s]*?(\d+)'
    loss_match = re.search(loss_pattern, final_answer, re.IGNORECASE)

    # Average duration (in seconds or minutes or formatted)
    avg_duration_pattern = r'(?:average|avg|mean)\s*(?:match)?\s*duration[:\s]*?(\d+(?:\.\d+)?)\s*(seconds?|secs?|minutes?|mins?)?'
    avg_duration_match = re.search(avg_duration_pattern, final_answer, re.IGNORECASE)

    # Validate extracted values
    if not total_match or not win_match or not loss_match or not avg_duration_match:
        return {"result": "others"}

    try:
        extracted_total = int(total_match.group(1))
        extracted_wins = int(win_match.group(1))
        extracted_losses = int(loss_match.group(1))
        extracted_avg_duration = float(avg_duration_match.group(1))
        duration_unit = avg_duration_match.group(2) if avg_duration_match.group(2) else 'seconds'

        # Convert to seconds if needed
        if 'min' in duration_unit.lower():
            extracted_avg_duration = extracted_avg_duration * 60

        # Verify total matches
        if extracted_total != expected_total:
            return {"result": "others"}

        # Verify wins
        if extracted_wins != expected_wins:
            return {"result": "others"}

        # Verify losses
        if extracted_losses != expected_losses:
            return {"result": "others"}

        # Verify average duration (allow 1% tolerance for rounding)
        if expected_avg_duration > 0:
            duration_diff = abs(extracted_avg_duration - expected_avg_duration)
            tolerance = max(1.0, expected_avg_duration * 0.01)
            if duration_diff > tolerance:
                return {"result": "others"}

        # Check for NA-East and Mythic Siege mentions
        if not re.search(r'NA-?East', final_answer, re.IGNORECASE):
            return {"result": "others"}

        if not re.search(r'Mythic\s*Siege', final_answer, re.IGNORECASE):
            return {"result": "others"}

        # All checks passed
        return {"result": "complete"}

    except (ValueError, AttributeError, IndexError):
        return {"result": "others"}

    return {"result": "others"}

