        has_extended_access = False
        for access_start, access_end in permissions:
            start_time = parse_time(access_start)
            end_time = parse_time(access_end)

            if start_time is None or end_time is None:
                continue

            # Check against all weekdays
            for weekday, hours in operational_schedule.items():
                if hours['open'] is None or hours['close'] is None:
                    continue

                # Sunday (weekday 6) with 00:00-00:00 means closed
                if weekday == 6 and hours['open'] == time(0, 0) and hours['close'] == time(0, 0):
