                        break
                else:
                    # Check if access extends before opening or after closing
                    if start_time < hours['open'] or end_time > hours['close']:
                        has_extended_access = True
                        break

            if has_extended_access:
                break

        if has_extended_access:
            passes_with_extended_access.append(pass_identifier)

