    if not final_answer:
        return {"result": "others"}

    # Expected passes: BW-EMP-001, BW-EMP-003, BW-VENDOR-01
    # All have permissions with 07:00-21:00 which extends beyond building hours (08:00-20:00)
    expected_passes = ['BW-EMP-001', 'BW-EMP-003', 'BW-VENDOR-01']

    if len(passes_with_extended_access) == 0:
        return {"result": "others"}

    # Check if all expected passes are found in passes_with_extended_access
    found_count = 0
    for expected_pass in expected_passes:
