    # Check that priorities are non-increasing as we go through time
    prev_priority_rank = float('inf')
    for task in final_sorted:
        task_priority = task[4]
        current_rank = priority_rank.get(task_priority, 0)

        # If we encounter a higher priority task after a lower priority one, ordering is wrong
        if current_rank > prev_priority_rank:
            return {"result": "others"}

        prev_priority_rank = current_rank

    # Verify scheduled_end times remain feasible
    for task_id in final_map:
        start_time = final_map[task_id][0]
