def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import json
    import re
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Calculate date 30 days ago from 2025-12-30 (the current date in the database)
    reference_date = datetime(2025, 12, 30, 12, 39, 2)
    date_30_days_ago = reference_date - timedelta(days=30)
    date_30_days_ago_str = date_30_days_ago.strftime('%Y-%m-%d %H:%M:%S')

    # Check for new records in notes table
    initial_notes = safe_query(initial_db_path, 
        "SELECT id, label, content_text, content_json FROM notes WHERE user_id = ? AND label LIKE '%Monthly yield summary%'",
        (1,))
    final_notes = safe_query(final_db_path,
        "SELECT id, label, content_text, content_json FROM notes WHERE user_id = ? AND label LIKE '%Monthly yield summary%'",
        (1,))

    # Check for new records in saved_reports table
    initial_reports = safe_query(initial_db_path,
        "SELECT id, label, content_json FROM saved_reports WHERE user_id = ? AND label LIKE '%Monthly yield summary%'",
        (1,))
    final_reports = safe_query(final_db_path,
        "SELECT id, label, content_json FROM saved_reports WHERE user_id = ? AND label LIKE '%Monthly yield summary%'",
        (1,))

    # Find new records
    new_note = None
    if len(final_notes) > len(initial_notes):
        initial_ids = {row[0] for row in initial_notes}
        for row in final_notes:
            if row[0] not in initial_ids and 'last 30 days' in row[1].lower():
                new_note = row
                break

    new_report = None
    if len(final_reports) > len(initial_reports):
        initial_ids = {row[0] for row in initial_reports}
        for row in final_reports:
            if row[0] not in initial_ids and 'last 30 days' in row[1].lower():
                new_report = row
                break

    # Must have at least one new record
    if not new_note and not new_report:
        return {"result": "others"}

    # Query transactions for interest_credit and staking_reward in the past 30 days
    transactions = safe_query(final_db_path,
        """SELECT asset_id, tx_type, amount 
           FROM transactions 
           WHERE user_id = ? 
           AND tx_type IN ('interest_credit', 'staking_reward')
           AND occurred_at >= ?
           ORDER BY asset_id""",
        (1, date_30_days_ago_str))

    # Aggregate by asset
    asset_totals = {}
    for asset_id, tx_type, amount in transactions:
        if asset_id not in asset_totals:
            asset_totals[asset_id] = {'interest': 0.0, 'rewards': 0.0, 'total': 0.0}

        if tx_type == 'interest_credit':
            asset_totals[asset_id]['interest'] += amount
        elif tx_type == 'staking_reward':
            asset_totals[asset_id]['rewards'] += amount
        asset_totals[asset_id]['total'] += amount

    # If no transactions found, cannot verify
    if not asset_totals:
        return {"result": "others"}

    # Get asset symbols for validation
    asset_symbols = {}
    for asset_id in asset_totals.keys():
        asset_info = safe_query(final_db_path, "SELECT symbol FROM assets WHERE id = ?", (asset_id,))
        if asset_info:
            asset_symbols[asset_id] = asset_info[0][0]

    # Extract and validate content from the new record
    content_to_check = None
    if new_note:
        content_to_check = new_note[2] if new_note[2] else new_note[3]  # content_text or content_json
    elif new_report:
        content_to_check = new_report[2]  # content_json

    if not content_to_check:
        return {"result": "others"}

    # Try to parse as JSON first
    try:
        parsed_content = json.loads(content_to_check)
        content_str = json.dumps(parsed_content).lower()
    except (json.JSONDecodeError, TypeError):
        content_str = str(content_to_check).lower()

    # Verify each asset's totals are represented in the content
    matched_assets = 0
    for asset_id, totals in asset_totals.items():
        symbol = asset_symbols.get(asset_id, '').lower()
        total_amount = totals['total']

        # Check if asset symbol appears in content
        if symbol and symbol in content_str:
            # Check if the total amount appears (with some tolerance for formatting)
            amount_str = str(total_amount)
            amount_patterns = [
                re.escape(amount_str),
                re.escape(f"{total_amount:.1f}"),
                re.escape(f"{total_amount:.2f}"),
                str(int(total_amount)) if total_amount == int(total_amount) else None
            ]

            for pattern in amount_patterns:
                if pattern and re.search(pattern, content_str):
                    matched_assets += 1
                    break

    # At least some assets must be matched in the content
    if matched_assets >= len(asset_totals) * 0.5:  # At least 50% of assets matched
        return {"result": "complete"}

    return {"result": "others"}

