def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Reference time from the database (2025-12-30 12:39:02)
    reference_time = datetime(2025, 12, 30, 12, 39, 2)
    time_48h_later = reference_time + timedelta(hours=48)

    # Step 1: Find all active staking positions for user_id=1 from initial state
    initial_active_positions = safe_query(
        initial_db_path,
        "SELECT id, staking_pool_id, staked_amount FROM staking_positions WHERE user_id = 1 AND status = 'active'"
    )

    if not initial_active_positions:
        return {"result": "others"}

    # Step 2: Determine which positions should be affected (have maintenance within 48h)
    affected_position_ids = []
    expected_unstakes = {}

    for pos_id, pool_id, staked_amount in initial_active_positions:
        # Check if this pool has maintenance window within 48 hours
        maint_windows = safe_query(
            initial_db_path,
            "SELECT start_time FROM maintenance_windows WHERE staking_pool_id = ?",
            (pool_id,)
        )

        has_maintenance_soon = False
        for (start_time_str,) in maint_windows:
            try:
                start_time = datetime.strptime(start_time_str, '%Y-%m-%d %H:%M:%S')
                if reference_time <= start_time <= time_48h_later:
                    has_maintenance_soon = True
                    break
            except:
                continue

        if has_maintenance_soon:
            affected_position_ids.append(pos_id)
            expected_unstakes[pos_id] = {
                'original_amount': staked_amount,
                'unstake_20_percent': staked_amount * 0.2,
                'remaining_80_percent': staked_amount * 0.8
            }

    # If no positions should be affected, return others
    if not affected_position_ids:
        return {"result": "others"}

    # Step 3: Verify partial_unstake events were created for affected positions
    for pos_id in affected_position_ids:
        # Get initial events count
        initial_events = safe_query(
            initial_db_path,
            "SELECT COUNT(*) FROM staking_position_events WHERE staking_position_id = ? AND event_type = 'partial_unstake'",
            (pos_id,)
        )
        initial_count = initial_events[0][0] if initial_events else 0

        # Get final events
        final_events = safe_query(
            final_db_path,
            "SELECT amount FROM staking_position_events WHERE staking_position_id = ? AND event_type = 'partial_unstake'",
            (pos_id,)
        )

        # Should have exactly one more partial_unstake event
        if len(final_events) != initial_count + 1:
            return {"result": "others"}

        # Get the new event amount (last one added)
        new_event_amounts = [amt for (amt,) in final_events[initial_count:]]
        if not new_event_amounts:
            return {"result": "others"}

        unstake_amount = new_event_amounts[0]
        expected_unstake = expected_unstakes[pos_id]['unstake_20_percent']

        # Allow small floating point tolerance
        if abs(unstake_amount - expected_unstake) > 0.01:
            return {"result": "others"}

    # Step 4: Verify staking_positions were updated to 80% of original
    for pos_id in affected_position_ids:
        final_position = safe_query(
            final_db_path,
            "SELECT staked_amount, status FROM staking_positions WHERE id = ?",
            (pos_id,)
        )

        if not final_position:
            return {"result": "others"}

        final_staked, status = final_position[0]
        expected_remaining = expected_unstakes[pos_id]['remaining_80_percent']

        # Position should still be active
        if status != 'active':
            return {"result": "others"}

        # Check if staked_amount is now 80% of original
        if abs(final_staked - expected_remaining) > 0.01:
            return {"result": "others"}

    # Step 5: Verify staking_unstake transactions were created
    initial_unstake_txns = safe_query(
        initial_db_path,
        "SELECT COUNT(*) FROM transactions WHERE user_id = 1 AND tx_type = 'staking_unstake'"
    )
    initial_unstake_count = initial_unstake_txns[0][0] if initial_unstake_txns else 0

    final_unstake_txns = safe_query(
        final_db_path,
        "SELECT staking_position_id, amount, wallet_id_to FROM transactions WHERE user_id = 1 AND tx_type = 'staking_unstake'"
    )

    # Should have new transactions for each affected position
    new_txns = final_unstake_txns[initial_unstake_count:]
    if len(new_txns) != len(affected_position_ids):
        return {"result": "others"}

    # Verify each transaction
    txn_position_ids = set()
    for pos_id, amount, wallet_to in new_txns:
        if pos_id not in affected_position_ids:
            return {"result": "others"}

        # Check amount matches 20% unstake
        expected_unstake = expected_unstakes[pos_id]['unstake_20_percent']
        if abs(amount - expected_unstake) > 0.01:
            return {"result": "others"}

        # Check it goes to primary wallet (wallet_id=1)
        if wallet_to != 1:
            return {"result": "others"}

        txn_position_ids.add(pos_id)

    # Ensure all affected positions have transactions
    if txn_position_ids != set(affected_position_ids):
        return {"result": "others"}

    # Step 6: Verify unaffected positions were NOT modified
    unaffected_position_ids = [pid for pid, _, _ in initial_active_positions if pid not in affected_position_ids]

    for pos_id in unaffected_position_ids:
        initial_pos = safe_query(
            initial_db_path,
            "SELECT staked_amount FROM staking_positions WHERE id = ?",
            (pos_id,)
        )
        final_pos = safe_query(
            final_db_path,
            "SELECT staked_amount FROM staking_positions WHERE id = ?",
            (pos_id,)
        )

        if not initial_pos or not final_pos:
            return {"result": "others"}

        # Staked amount should be unchanged
        if abs(initial_pos[0][0] - final_pos[0][0]) > 0.01:
            return {"result": "others"}

    # All checks passed
    return {"result": "complete"}

