    # Step 1: Verify the AML Policy exists and get its policy_id
    policy_query = "SELECT id FROM policies WHERE name = 'Anti-Money Laundering (AML) Policy)'"
    policy_results = safe_query(final_db_path, policy_query)

    if not policy_results:
        return {"result": "others"}

    policy_id = policy_results[0][0]

    # Step 2: Get all versions of this policy in initial state
    initial_versions_query = "SELECT id, version_number, status, effective_date FROM policy_versions WHERE policy_id = ? ORDER BY id"
    initial_versions = safe_query(initial_db_path, initial_versions_query, (policy_id,))

    # Step 3: Get all versions of this policy in final state
    final_versions = safe_query(final_db_path, initial_versions_query, (policy_id,))

    if not initial_versions or not final_versions:
        return {"result": "others"}

    # Convert to dictionaries for easier lookup
    initial_dict = {v[0]: {'version_number': v[1], 'status': v[2], 'effective_date': v[3]} for v in initial_versions}
    final_dict = {v[0]: {'version_number': v[1], 'status': v[2], 'effective_date': v[3]} for v in final_versions}

    # Step 4: Identify the latest draft version in initial state (should be version_id=1003)
    latest_draft_id = None
    for v_id, v_data in initial_dict.items():
        if v_data['status'] == 'draft':
            latest_draft_id = v_id
            break

    if latest_draft_id is None:
        return {"result": "others"}

    # Step 5: Check if the latest draft is now published with effective_date='2026-03-15'
    if latest_draft_id not in final_dict:
        return {"result": "others"}

    final_draft = final_dict[latest_draft_id]
    if final_draft['status'] != 'published' or final_draft['effective_date'] != '2026-03-15':
        return {"result": "others"}

    # Step 6: Check if previously published versions are now superseded
    previously_published = [v_id for v_id, v_data in initial_dict.items() if v_data['status'] == 'published']

    if not previously_published:
        # No previously published versions is unusual but might be valid
        # However, from initial state we know 1001 and 1002 were published
        return {"result": "others"}

    for v_id in previously_published:
        if v_id not in final_dict:
            return {"result": "others"}
        if final_dict[v_id]['status'] != 'superseded':
            return {"result": "others"}

    # Step 7: Verify that the changes were NOT present in initial state
    if initial_dict[latest_draft_id]['status'] == 'published':
        return {"result": "others"}

    if initial_dict[latest_draft_id]['effective_date'] == '2026-03-15':
        return {"result": "others"}

    for v_id in previously_published:
        if initial_dict[v_id]['status'] == 'superseded':
            return {"result": "others"}

    # All checks passed
    return {"result": "complete"}

