def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    if not final_answer or len(final_answer.strip()) < 50:
        return {"result": "others"}

    # Calculate date ranges
    # Assume current date is around 2026-01-05 based on the latest data in DB
    current_date = datetime(2026, 1, 5)
    ninety_days_ago = current_date - timedelta(days=90)
    twelve_months_ago = current_date - timedelta(days=365)

    # Part 1: AML policy acknowledgment completion rate for last 90 days
    # Find published AML policy versions
    aml_query = """
        SELECT pv.id, pa.id as assignment_id, pa.completion_status, pak.id as ack_id
        FROM policy_versions pv
        JOIN policies p ON pv.policy_id = p.id
        LEFT JOIN policy_assignments pa ON pv.id = pa.policy_version_id
        LEFT JOIN policy_acknowledgments pak ON pv.id = pak.policy_version_id AND pa.user_id = pak.user_id
        WHERE p.category = 'financial_crime' 
        AND p.name LIKE '%AML%'
        AND pv.status = 'published'
        AND pv.effective_date >= ?
    """

    aml_results = safe_query(final_db_path, aml_query, (ninety_days_ago.strftime('%Y-%m-%d'),))

    if not aml_results:
        return {"result": "others"}

    # Calculate completion rate
    total_assignments = len([r for r in aml_results if r[1] is not None])
    completed_assignments = len([r for r in aml_results if r[1] is not None and r[3] is not None])

    if total_assignments == 0:
        expected_rate = 0.0
    else:
        expected_rate = (completed_assignments / total_assignments) * 100

    # Look for rate/percentage in final_answer
    rate_pattern = r'(\d+\.?\d*)\s*%|rate[^\d]*(\d+\.?\d*)|completion[^\d]*(\d+\.?\d*)'
    rate_matches = re.findall(rate_pattern, final_answer, re.IGNORECASE)

    found_rate = False
    for match in rate_matches:
        for group in match:
            if group:
                try:
                    reported_rate = float(group)
                    if abs(reported_rate - expected_rate) < 1.0:
                        found_rate = True
                        break
                except ValueError:
                    continue
        if found_rate:
            break

    # Check for mentions of AML
    if not re.search(r'AML|anti[\s-]money[\s-]laundering', final_answer, re.IGNORECASE):
        return {"result": "others"}

    # Part 2: Overdue assessments grouped by assignee
    overdue_query = """
        SELECT a.id, a.name, t.name as team_name
        FROM assessments a
        LEFT JOIN teams t ON a.assignee_team_id = t.id
        WHERE a.status = 'overdue'
    """

    overdue_results = safe_query(final_db_path, overdue_query)

    if not overdue_results:
        return {"result": "others"}

    # Check for overdue mentions
    if not re.search(r'overdue', final_answer, re.IGNORECASE):
        return {"result": "others"}

    # Look for team/assignee names
    found_assignee = False
    for row in overdue_results:
        team_name = row[2] if row[2] else ""
        if team_name and re.search(re.escape(team_name), final_answer, re.IGNORECASE):
            found_assignee = True
            break

    # Part 3: Open and investigating incidents by category and severity for last 12 months
    incidents_query = """
        SELECT category, severity, COUNT(*) as count
        FROM incidents
        WHERE status IN ('open', 'investigating')
        AND discovery_date >= ?
        GROUP BY category, severity
    """

    incidents_results = safe_query(final_db_path, incidents_query, (twelve_months_ago.strftime('%Y-%m-%d'),))

    if not incidents_results:
        return {"result": "others"}

    # Check for incident mentions
    if not re.search(r'incident', final_answer, re.IGNORECASE):
        return {"result": "others"}

    # Check for status mentions (open/investigating)
    if not re.search(r'open|investigating', final_answer, re.IGNORECASE):
        return {"result": "others"}

    # Verify incident counts are present
    found_incident_count = False
    for row in incidents_results:
        category = row[0]
        severity = row[1]
        count = row[2]

        # Look for this specific count in the report
        if str(count) in final_answer:
            found_incident_count = True
            break

    # Check for category and severity mentions
    if not re.search(r'category|severity', final_answer, re.IGNORECASE):
        return {"result": "others"}

    # All three components must be present
    if found_rate and found_assignee and found_incident_count:
        return {"result": "complete"}

    return {"result": "others"}

