def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Step 1: Find the main dining room ID
    main_room_query = "SELECT id FROM dining_rooms WHERE is_main = 1 LIMIT 1"
    main_room_initial = safe_query(initial_db_path, main_room_query)

    if not main_room_initial:
        return {"result": "others"}

    main_room_id = main_room_initial[0][0]

    # Step 2: Get current timestamp from the database to determine "20 minutes ago"
    # Use the database's CURRENT_TIMESTAMP for consistency
    current_time_query = "SELECT CURRENT_TIMESTAMP"
    current_time_result = safe_query(initial_db_path, current_time_query)

    if not current_time_result:
        return {"result": "others"}

    try:
        current_time_str = current_time_result[0][0]
        current_time = datetime.strptime(current_time_str, "%Y-%m-%d %H:%M:%S")
    except Exception:
        return {"result": "others"}

    twenty_minutes_ago = current_time - timedelta(minutes=20)

    # Step 3: Get all tables in main dining room from initial state
    tables_query = "SELECT id, table_number, status, last_seated_at FROM tables WHERE dining_room_id = ?"
    initial_tables = safe_query(initial_db_path, tables_query, (main_room_id,))

    if not initial_tables:
        return {"result": "others"}

    # Step 4: Identify tables that should be updated
    # (status = 'dirty' AND last_seated_at > 20 minutes ago)
    tables_to_update = []
    dirty_but_recent = []  # Should NOT be updated

    for table_id, table_number, status, last_seated_at in initial_tables:
        if status == 'dirty':
            if last_seated_at:
                try:
                    last_seated_time = datetime.strptime(last_seated_at, "%Y-%m-%d %H:%M:%S")
                    if last_seated_time < twenty_minutes_ago:
                        tables_to_update.append(table_id)
                    else:
                        dirty_but_recent.append(table_id)
                except Exception:
                    # If timestamp parsing fails, skip this table
                    continue
            # If last_seated_at is NULL, we cannot determine age, so don't update

    # Step 5: Get final state of tables
    final_tables = safe_query(final_db_path, tables_query, (main_room_id,))

    if not final_tables:
        return {"result": "others"}

    # Create dictionaries for easy lookup
    initial_status_map = {row[0]: row[2] for row in initial_tables}
    final_status_map = {row[0]: row[2] for row in final_tables}

    # Step 6: Verify that tables_to_update were changed to 'free'
    for table_id in tables_to_update:
        if table_id not in final_status_map:
            return {"result": "others"}

        if final_status_map[table_id] != 'free':
            # Table should have been updated but wasn't
            return {"result": "others"}

    # Step 7: Verify that dirty_but_recent tables remain 'dirty'
    for table_id in dirty_but_recent:
        if table_id not in final_status_map:
            return {"result": "others"}

        if final_status_map[table_id] != 'dirty':
            # Table should NOT have been updated but was
            return {"result": "others"}

    # Step 8: Verify no other tables changed status incorrectly
    for table_id in initial_status_map:
        if table_id in tables_to_update:
            # Already verified above
            continue

        if table_id not in final_status_map:
            return {"result": "others"}

        # For tables not in tables_to_update, status should remain unchanged
        # unless they were already in a different state
        initial_status = initial_status_map[table_id]
        final_status = final_status_map[table_id]

        if table_id not in dirty_but_recent:
            # Non-dirty tables or dirty tables without proper last_seated_at
            # should not change
            if initial_status != 'dirty' and initial_status != final_status:
                return {"result": "others"}

    # Step 9: Final check - at least one table should have been updated if there were any to update
    if len(tables_to_update) > 0:
        # Verify at least one change was made
        changes_made = False
        for table_id in tables_to_update:
            if initial_status_map.get(table_id) != final_status_map.get(table_id):
                changes_made = True
                break

        if not changes_made:
            return {"result": "others"}

    # All checks passed
    return {"result": "complete"}

