        return {"result": "others"}

    # Look for promo code placeholder in body (various formats)
    combined_body = f"{body_html or ''} {body_text or ''}"
    promo_code_placeholder_found = False

    # Check for common placeholder patterns
    if (re.search(r'\{\{[^}]*promo[^}]*code[^}]*\}\}', combined_body, re.IGNORECASE) or
        re.search(r'\{[^}]*promo[^}]*code[^}]*\}', combined_body, re.IGNORECASE) or
        re.search(r'\[\[[^\]]*promo[^\]]*code[^\]]*\]\]', combined_body, re.IGNORECASE) or
        re.search(r'promo[_\s-]*code', combined_body, re.IGNORECASE)):
        promo_code_placeholder_found = True

    if not promo_code_placeholder_found:
        return {"result": "others"}

    # Verify an end step exists as child of the condition step
    end_step_found = False
    for step in final_steps:
        step_id, step_type, name, condition_json, parent_step_id, branch_type = step
        if step_type == 'end' and parent_step_id == condition_step:
            end_step_found = True
            break

    if not end_step_found:
        return {"result": "others"}

    # All checks passed
    return {"result": "complete"}

def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Get initial and final summary counts
    initial_summaries = safe_query(initial_db_path, "SELECT * FROM kitchen_performance_summaries ORDER BY id")
    final_summaries = safe_query(final_db_path, "SELECT * FROM kitchen_performance_summaries ORDER BY id")

    # Check if a new summary was added
    if len(final_summaries) <= len(initial_summaries):
        return {"result": "others"}

    # Get the new summary (last one added)
    new_summary = final_summaries[-1]
    if len(new_summary) < 9:
        return {"result": "others"}

    (summary_id, timeframe_start, timeframe_end, late_count, avg_lateness,
     top_station1_id, top_station1_load, top_station2_id, top_station2_load,
     generated_at, generated_by) = new_summary[:11]

    # Determine the reference time (latest timestamp in the database)
    latest_time_query = """
        SELECT MAX(completed_time) FROM order_tickets WHERE completed_time IS NOT NULL
    """
    latest_times = safe_query(final_db_path, latest_time_query)
    if not latest_times or not latest_times[0][0]:
        return {"result": "others"}

    latest_time_str = latest_times[0][0]
    try:
        latest_time = datetime.fromisoformat(latest_time_str.replace(' ', 'T'))
    except Exception:
        return {"result": "others"}

    two_hours_ago = latest_time - timedelta(hours=2)

    # Verify timeframe is approximately the last 2 hours
    try:
        start_time = datetime.fromisoformat(timeframe_start.replace(' ', 'T'))
        end_time = datetime.fromisoformat(timeframe_end.replace(' ', 'T'))
    except Exception:
        return {"result": "others"}

    # Check if timeframe is roughly 2 hours and ends near the latest time
    time_diff = (end_time - start_time).total_seconds() / 3600
    if not (1.8 <= time_diff <= 2.2):
        return {"result": "others"}

    # Get late tickets from the database (completed_time > due_time + 10 minutes)
    late_tickets_query = """
        SELECT id, ticket_number, due_time, completed_time,
               (julianday(completed_time) - julianday(due_time)) * 24 * 60 as lateness_minutes
        FROM order_tickets
        WHERE status = 'completed'
          AND completed_time IS NOT NULL
          AND completed_time >= ?
          AND completed_time <= ?
          AND (julianday(completed_time) - julianday(due_time)) * 24 * 60 > 10
    """
    late_tickets = safe_query(final_db_path, late_tickets_query, (timeframe_start, timeframe_end))

    if len(late_tickets) == 0:
        # If no late tickets, the summary should reflect that
        if late_count != 0:
            return {"result": "others"}
    else:
        # Verify late ticket count
        if late_count != len(late_tickets):
            return {"result": "others"}

        # Calculate expected average lateness
        total_lateness = sum(ticket[4] for ticket in late_tickets)
        expected_avg = total_lateness / len(late_tickets)

        # Allow small floating point difference (within 0.5 minutes)
        if abs(avg_lateness - expected_avg) > 0.5:
            return {"result": "others"}

    # Get station loads for the timeframe
    station_load_query = """
        SELECT station_id, COUNT(*) as task_count
        FROM station_tasks
        WHERE (scheduled_start_time >= ? AND scheduled_start_time <= ?)
           OR (actual_start_time >= ? AND actual_start_time <= ?)
        GROUP BY station_id
        ORDER BY task_count DESC
        LIMIT 2
    """
    station_loads = safe_query(final_db_path, station_load_query,
                               (timeframe_start, timeframe_end, timeframe_start, timeframe_end))

    if len(station_loads) >= 2:
        expected_top1_id = station_loads[0][0]
        expected_top1_load = station_loads[0][1]
        expected_top2_id = station_loads[1][0]
        expected_top2_load = station_loads[1][1]

        # Verify top stations match
        if top_station1_id != expected_top1_id or top_station2_id != expected_top2_id:
            return {"result": "others"}

        # Verify station loads are correct
        if abs(top_station1_load - expected_top1_load) > 0.1 or abs(top_station2_load - expected_top2_load) > 0.1:
            return {"result": "others"}
    elif len(station_loads) == 1:
        if top_station1_id != station_loads[0][0]:
            return {"result": "others"}
    else:
        # No station tasks in timeframe
        if top_station1_id is not None or top_station2_id is not None:
            return {"result": "others"}

    # Optionally verify final_answer contains key metrics
    if final_answer:
        # Check for late ticket count
        if not re.search(rf'\b{late_count}\b.*late.*ticket', final_answer, re.IGNORECASE | re.DOTALL):
            if not re.search(rf'late.*ticket.*\b{late_count}\b', final_answer, re.IGNORECASE | re.DOTALL):
                return {"result": "others"}

        # Check for average lateness (allow for rounding)
        avg_pattern = rf'\b{int(avg_lateness)}\b|\b{round(avg_lateness, 1)}\b|\b{round(avg_lateness, 2)}\b'
        if not re.search(avg_pattern, final_answer):
            return {"result": "others"}

    return {"result": "complete"}

def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re
    from datetime import datetime, timedelta

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Step 1: Find Luna's pet_id in final database
    luna_query = "SELECT id, user_id FROM pets WHERE name = ?"
    luna_results = safe_query(final_db_path, luna_query, ('Luna',))

    if not luna_results:
        return {"result": "others"}

    luna_pet_id = luna_results[0][0]

    # Step 2: Find care plan with exact name for Luna
    care_plan_query = "SELECT id, pet_id, name, description FROM care_plans WHERE pet_id = ? AND name = ?"
    care_plan_results = safe_query(final_db_path, care_plan_query, (luna_pet_id, 'Annual Wellness and Prevention'))

    if not care_plan_results:
        return {"result": "others"}

    care_plan_id = care_plan_results[0][0]

    # Step 3: Verify care plan items
    items_query = "SELECT id, item_type, name, frequency FROM care_plan_items WHERE care_plan_id = ?"
    items_results = safe_query(final_db_path, items_query, (care_plan_id,))

    if len(items_results) != 3:
        return {"result": "others"}

    # Check for required items
    required_items = {
        'appointment': {'found': False, 'frequency_check': False, 'id': None},
        'medication': {'found': False, 'frequency_check': False, 'id': None},
        'vaccine': {'found': False, 'frequency_check': False, 'id': None}
    }

    for item in items_results:
        item_id, item_type, name, frequency = item

        if item_type == 'appointment':
            # Check for annual exam reference
            if re.search(r'annual.*exam', name, re.IGNORECASE):
                required_items['appointment']['found'] = True
                required_items['appointment']['id'] = item_id
                # Check frequency is yearly
                if frequency and re.search(r'year', frequency, re.IGNORECASE):
                    required_items['appointment']['frequency_check'] = True

        elif item_type == 'medication':
            # Check for flea prevention
            if re.search(r'flea.*prevent', name, re.IGNORECASE):
                required_items['medication']['found'] = True
                required_items['medication']['id'] = item_id
                # Check frequency is monthly
                if frequency and re.search(r'month', frequency, re.IGNORECASE):
                    required_items['medication']['frequency_check'] = True

        elif item_type == 'vaccine':
            # Check for core vaccines
            if re.search(r'core.*vaccine|vaccine.*core', name, re.IGNORECASE):
                required_items['vaccine']['found'] = True
                required_items['vaccine']['id'] = item_id
                # Check frequency is yearly
                if frequency and re.search(r'year', frequency, re.IGNORECASE):
                    required_items['vaccine']['frequency_check'] = True

    # Verify all required items are found with correct frequencies
    for item_type, checks in required_items.items():
        if not checks['found'] or not checks['frequency_check']:
            return {"result": "others"}

    # Step 4: Verify reminders exist with correct configuration
    item_ids = [checks['id'] for checks in required_items.values() if checks['id']]

    if len(item_ids) != 3:
        return {"result": "others"}

    reminders_query = "SELECT id, care_plan_item_id, due_date, notify_at, delivery_channel, status FROM care_plan_reminders WHERE pet_id = ? AND care_plan_item_id IN ({0})".format(','.join('?' * len(item_ids)))
    reminders_params = tuple([luna_pet_id] + item_ids)
    reminders_results = safe_query(final_db_path, reminders_query, reminders_params)

    # We need at least one reminder per item (could be multiple if recurring)
    if len(reminders_results) < 3:
        return {"result": "others"}

    # Verify reminder properties
    email_count = 0
    seven_day_advance_count = 0

    for reminder in reminders_results:
        reminder_id, item_id, due_date, notify_at, delivery_channel, status = reminder

        # Check delivery channel is email
        if delivery_channel == 'email':
            email_count += 1

        # Check notify_at is 7 days before due_date
        if due_date and notify_at:
            try:
                # Parse dates - handle both datetime and date formats
                if ' ' in str(due_date):
                    due_dt = datetime.strptime(str(due_date).split('.')[0], '%Y-%m-%d %H:%M:%S')
                else:
                    due_dt = datetime.strptime(str(due_date), '%Y-%m-%d')

                if ' ' in str(notify_at):
                    notify_dt = datetime.strptime(str(notify_at).split('.')[0], '%Y-%m-%d %H:%M:%S')
                else:
                    notify_dt = datetime.strptime(str(notify_at), '%Y-%m-%d')

                # Calculate difference
                diff = (due_dt - notify_dt).days

                # Check if difference is approximately 7 days (allow 6-8 days for time variations)
                if 6 <= diff <= 8:
                    seven_day_advance_count += 1
            except Exception:
                pass

        # Check status is scheduled
        if status != 'scheduled':
            return {"result": "others"}

    # Verify we have email reminders with 7-day advance notice
    if email_count < 3 or seven_day_advance_count < 3:
        return {"result": "others"}

    return {"result": "complete"}

def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re
