            return results
        except Exception:
            return []

    # Check if final_answer exists and has content
    if not final_answer or len(final_answer.strip()) < 50:
        return {"result": "others"}

    # Query for member_account_id 2045 transactions
    query = """
        SELECT id, transaction_date, transaction_type, source_type, 
               points_earned, points_debited, expiry_date
        FROM points_transactions
        WHERE member_account_id = 2045
        ORDER BY transaction_date DESC
    """

    transactions = safe_query(final_db_path, query)

    if not transactions:
        return {"result": "others"}

    # Find the latest transaction date to calculate 6 months back
    latest_date_str = transactions[0][1]  # transaction_date of most recent
    try:
        latest_date = datetime.strptime(latest_date_str, '%Y-%m-%d %H:%M:%S')
    except:
        try:
            latest_date = datetime.strptime(latest_date_str.split()[0], '%Y-%m-%d')
        except:
            return {"result": "others"}

    six_months_ago = latest_date - timedelta(days=180)

    # Filter transactions from last 6 months
    recent_transactions = []
    for txn in transactions:
        txn_date_str = txn[1]
        try:
            txn_date = datetime.strptime(txn_date_str, '%Y-%m-%d %H:%M:%S')
        except:
            try:
                txn_date = datetime.strptime(txn_date_str.split()[0], '%Y-%m-%d')
            except:
                continue

        if txn_date >= six_months_ago:
            recent_transactions.append(txn)

    if not recent_transactions:
        return {"result": "others"}

    # Calculate expected summary values
    total_earned = sum(txn[4] for txn in recent_transactions)  # points_earned
    total_debited = sum(txn[5] for txn in recent_transactions)  # points_debited

    # Calculate points expiring in next 30 days from today
    today = datetime.now()
    thirty_days_later = today + timedelta(days=30)

    points_expiring_soon = 0
    for txn in recent_transactions:
        expiry_str = txn[6]  # expiry_date
        if expiry_str:
            try:
                expiry_date = datetime.strptime(expiry_str, '%Y-%m-%d')
                if today <= expiry_date <= thirty_days_later:
                    points_expiring_soon += txn[4]  # Add points_earned
            except:
                pass

    # Normalize final_answer for checking
    answer_lower = final_answer.lower()
    answer_normalized = re.sub(r'\s+', ' ', answer_lower)

    # Check 1: Verify all required transaction fields are mentioned
    required_fields = ['points_earned', 'points_debited', 'source', 'expiry_date']
    fields_mentioned = 0
    for field in required_fields:
        # Check for variations of field names
        field_variations = [field, field.replace('_', ' '), field.replace('_', '')]
        if any(var in answer_normalized for var in field_variations):
            fields_mentioned += 1

    if fields_mentioned < 3:  # At least 3 of 4 key fields should be mentioned
        return {"result": "others"}

    # Check 2: Verify transaction count is reasonable (at least mention of multiple transactions)
    num_transactions = len(recent_transactions)
    transaction_indicators = ['transaction', 'ledger', 'record', 'entry', 'entries']
    has_transaction_context = any(ind in answer_normalized for ind in transaction_indicators)

    if not has_transaction_context:
        return {"result": "others"}

    # Check 3: Verify summary section exists
    summary_keywords = ['summary', 'total', 'computed', 'calculation']
    has_summary_section = any(kw in answer_normalized for kw in summary_keywords)

    if not has_summary_section:
        return {"result": "others"}

    # Check 4: Verify computed values are present in final_answer
    # Look for total earned points
    has_total_earned = False
    if str(total_earned) in final_answer:
        if (re.search(rf'(total.*earned|earned.*total|total.*points).*{total_earned}', answer_normalized, re.DOTALL) or
            re.search(rf'{total_earned}.*(earned|total)', answer_normalized)):
            has_total_earned = True

    # Look for total redeemed/debited points
    has_total_debited = False
    if str(total_debited) in final_answer:
        if (re.search(rf'(total.*(redeem|debit)|redeem.*total|debit.*total).*{total_debited}', answer_normalized, re.DOTALL) or
            re.search(rf'{total_debited}.*(redeem|debit)', answer_normalized)):
            has_total_debited = True

    # Look for points expiring soon
    has_expiring_soon = False
    if str(points_expiring_soon) in final_answer:
        if (re.search(rf'(expir|next.*30|30.*day).*{points_expiring_soon}', answer_normalized, re.DOTALL) or
            re.search(rf'{points_expiring_soon}.*(expir|next.*30|30.*day)', answer_normalized, re.DOTALL)):
            has_expiring_soon = True

    # Check 5: Verify member_account_id 2045 is mentioned
    has_member_id = '2045' in final_answer

    if not has_member_id:
        return {"result": "others"}

    # Check 6: Verify at least 2 of 3 summary values are correctly mentioned
    summary_values_found = sum([has_total_earned, has_total_debited, has_expiring_soon])

    if summary_values_found < 2:
        return {"result": "others"}

    # Check 7: Verify source types are mentioned (order, manual_adjustment, reward, referral)
    source_mentions = 0
    for txn in recent_transactions:
        source_type = txn[3]  # source_type
        if source_type and source_type in answer_normalized:
            source_mentions += 1
            break  # At least one source type mentioned is good

    if source_mentions == 0:
        return {"result": "others"}

    # Check 8: Verify time period (6 months or 180 days) is mentioned
    time_period_keywords = ['6 months', 'six months', '180 days', 'last 6 months', 'past 6 months']
    has_time_period = any(kw in answer_normalized for kw in time_period_keywords)

    if not has_time_period:
        return {"result": "others"}

    # All critical checks passed
    return {"result": "complete"}

def verify_task_completion(initial_db_path: str, final_db_path: str, final_answer: str | None = None) -> dict:
    import sqlite3
    import re
    from datetime import datetime, timedelta

    if not final_answer or len(final_answer.strip()) < 10:
        return {"result": "others"}

    def safe_query(db_path: str, query: str, params: tuple = ()) -> list:
        try:
            conn = sqlite3.connect(f"file:{db_path}?mode=ro", uri=True)
            cursor = conn.cursor()
            cursor.execute(query, params)
            results = cursor.fetchall()
            conn.close()
            return results
        except Exception:
            return []

    # Get UrbanWear program_id
    program_query = "SELECT lp.id FROM loyalty_programs lp JOIN brands b ON lp.brand_id = b.id WHERE b.name = 'UrbanWear'"
    program_result = safe_query(final_db_path, program_query)
    if not program_result:
        return {"result": "others"}
    program_id = program_result[0][0]

    # Determine last quarter - use the latest tier_history change_date as reference
    max_date_query = "SELECT MAX(change_date) FROM tier_history WHERE program_id = ?"
    max_date_result = safe_query(final_db_path, max_date_query, (program_id,))
    if not max_date_result or not max_date_result[0][0]:
        return {"result": "others"}

    try:
        max_date_str = max_date_result[0][0]
        if ' ' in max_date_str:
            max_date = datetime.strptime(max_date_str, '%Y-%m-%d %H:%M:%S')
        else:
            max_date = datetime.strptime(max_date_str, '%Y-%m-%d')
        quarter_start = max_date - timedelta(days=90)
        quarter_start_str = quarter_start.strftime('%Y-%m-%d')
    except Exception:
        return {"result": "others"}

    # Query Silver to Gold transitions with earn_rule types
    silver_to_gold_query = """
        SELECT er.rule_type, COUNT(*) as count
        FROM tier_history th
        LEFT JOIN points_transactions pt ON th.source_type = pt.source_type AND th.source_id = pt.source_id
        LEFT JOIN earn_rules er ON pt.earn_rule_id = er.id
        WHERE th.program_id = ?
        AND th.previous_tier_id = 1
        AND th.new_tier_id = 2
        AND th.change_date >= ?
        GROUP BY er.rule_type
    """

    # Query Gold to Platinum transitions with earn_rule types
    gold_to_platinum_query = """
        SELECT er.rule_type, COUNT(*) as count
        FROM tier_history th
        LEFT JOIN points_transactions pt ON th.source_type = pt.source_type AND th.source_id = pt.source_id
        LEFT JOIN earn_rules er ON pt.earn_rule_id = er.id
        WHERE th.program_id = ?
        AND th.previous_tier_id = 2
        AND th.new_tier_id = 3
        AND th.change_date >= ?
        GROUP BY er.rule_type
    """

    silver_to_gold = safe_query(final_db_path, silver_to_gold_query, (program_id, quarter_start_str))
    gold_to_platinum = safe_query(final_db_path, gold_to_platinum_query, (program_id, quarter_start_str))

    # Build expected results dictionary
    expected_results = {
        'silver_to_gold': {},
        'gold_to_platinum': {}
    }

    for rule_type, count in silver_to_gold:
        if rule_type:
            expected_results['silver_to_gold'][rule_type.lower()] = count

    for rule_type, count in gold_to_platinum:
        if rule_type:
            expected_results['gold_to_platinum'][rule_type.lower()] = count

    # If no transitions found, check if answer indicates zero results
    if not expected_results['silver_to_gold'] and not expected_results['gold_to_platinum']:
        zero_patterns = [
            r'no.*transition',
            r'zero.*member',
            r'0.*member',
            r'none.*moved',
            r'empty.*result'
        ]
        for pattern in zero_patterns:
            if re.search(pattern, final_answer, re.IGNORECASE):
                return {"result": "complete"}
        return {"result": "others"}

    # Verify final_answer contains the expected results
    final_answer_lower = final_answer.lower()

    # Check for tier progression mentions
    tier_progression_patterns = [
        r'silver.*gold',
        r'gold.*platinum',
        r'tier.*progress',
        r'progression.*analys'
    ]
    has_tier_mention = any(re.search(p, final_answer_lower) for p in tier_progression_patterns)
    if not has_tier_mention:
        return {"result": "others"}

    # Check for earn rule type mentions
    earn_types = ['purchase', 'referral', 'check-in', 'check_in', 'checkin']
    mentioned_types = sum(1 for et in earn_types if et in final_answer_lower)
    if mentioned_types == 0:
        return {"result": "others"}

    # Verify specific counts for each transition and earn type
    verified_count = 0
    total_expected = 0

    for transition, type_counts in expected_results.items():
        for earn_type, expected_count in type_counts.items():
            total_expected += 1

            # Create flexible patterns to find the count
            earn_type_normalized = earn_type.replace('-', '[_\s-]*').replace('_', '[_\s-]*')
            transition_normalized = transition.replace('_', ' ').replace('-', ' ')

            patterns = [
                rf'{earn_type_normalized}[^0-9]*{expected_count}',
                rf'{expected_count}[^a-z]*{earn_type_normalized}',
                rf'{transition_normalized}[^0-9]*{earn_type_normalized}[^0-9]*{expected_count}'
            ]

            # Check if any pattern matches
            found = False
            for pattern in patterns:
                if re.search(pattern, final_answer_lower, re.IGNORECASE):
                    found = True
                    break

            if found:
                verified_count += 1

    # Require at least 50% of expected counts to be verified
    if total_expected > 0 and verified_count >= max(1, total_expected * 0.5):
        return {"result": "complete"}

    return {"result": "others"}
